// ================================================================
// PARSE & CLASSIFY INCIDENT EVENT — v9
//
// SUMBER TICKET (form_id di DB):
//   - 'static_portal'   : form statis di web portal Next.js
//   - 'formbricks'      : Formbricks webhook (FORM_ID_TICKETING / FORM_ID_INCIDENT)
//   - 'admin_portal'    : dibuat manual oleh admin
//   - 'chatbot_auto_create': dibuat oleh AI chatbot Discord
//
// JENIS EVENT:
//   ticket_created    — tiket baru (dari webhook.route.js atau portal)
//   status_update     — teknisi update status via Discord/admin panel
//   manual_broadcast  — admin push manual ke Discord
//
// DETEKSI INCIDENT:
//   - type='INCIDENT' → otomatis incident
//   - type='TICKETING' + keyword kritis → auto-detect sebagai incident
// ================================================================
const body = $input.item.json.body || $input.item.json;

const eventType  = (body.eventType  || 'ticket_created').toLowerCase();
const ticketId   = Number(body.ticketId || body.ticket_id || 0);
const ticketType = (body.ticketType || body.type || '').toUpperCase();
const newStatus  = (body.status     || '').toUpperCase();
const note       = body.note        || '';
const formId     = body.formId      || body.form_id || 'unknown';
const formFields = body.formFields  || body.form_fields || {};

if (!ticketId || isNaN(ticketId)) {
  console.log('[INC] Skip: no valid ticketId');
  return [{ json: { skip: true, reason: 'no ticketId' } }];
}

// ── Sumber form (hanya untuk logging/info, tidak mempengaruhi logika) ────────
const SOURCE_LABELS = {
  'static_portal':       'Web Portal (Static Form)',
  'formbricks':          'Formbricks',
  'admin_portal':        'Admin Panel',
  'chatbot_auto_create': 'Discord Chatbot',
};
// Formbricks form ID bisa berupa ID panjang, normalize ke label
const knownFormbricksIds = [
  'zcp7cbqqrtavbyd6wwkmk2vx',  // FORM_ID_TICKETING default
  'cmiobkjfm2piqad012scz1yxf', // FORM_ID_INCIDENT default
];
let sourceLabel = SOURCE_LABELS[formId] || formId;
if (knownFormbricksIds.includes(formId) || formId.length > 15) {
  sourceLabel = 'Formbricks';
}

// ── Keyword-based incident auto-detection ────────────────────────────────────
const INCIDENT_KW = [
  'down','outage','mati','tidak bisa','gangguan total','semua user','seluruh',
  'parah','kritis','critical','server','network','jaringan','database',
  'internet mati','tidak ada koneksi','offline','fail','failure'
];

const issueText = [
  formFields['Incident Information'] || '',
  formFields['Incident Title']       || '',
  formFields['Issue']                || '',
  formFields['Indicated Issue']      || '',
].join(' ').toLowerCase();

const autoDetected = ticketType === 'TICKETING' &&
  INCIDENT_KW.some(kw => issueText.includes(kw));

// ── Category detection ───────────────────────────────────────────────────────
const CATEGORIES = {
  network:     ['network','internet','jaringan','koneksi','wifi','lan','vpn'],
  system:      ['server','database','db','storage','os','windows','linux','backup'],
  application: ['aplikasi','app','web','portal','login','error','crash','bug'],
  hardware:    ['hardware','printer','komputer','pc','laptop','monitor','ups'],
  security:    ['security','hack','virus','ransomware','breach','akses tidak sah'],
};
const suspectArea = (formFields['Suspect Area'] || '').toLowerCase();
let category = 'general';
for (const [cat, kws] of Object.entries(CATEGORIES)) {
  if (kws.some(kw => issueText.includes(kw) || suspectArea.includes(kw))) {
    category = cat;
    break;
  }
}

const isIncidentTicket = ticketType === 'INCIDENT' || autoDetected;

console.log(`[INC] eventType=${eventType} | ticketId=#${ticketId} | type=${ticketType} | source=${sourceLabel} | isIncident=${isIncidentTicket} | category=${category} | autoDetected=${autoDetected}`);

return [{ json: {
  skip:          false,
  eventType,
  ticketId,
  ticketType,
  newStatus,
  note,
  formId,
  sourceLabel,
  formFields,
  category,
  isIncidentTicket,
  autoDetected,
} }];

// ================================================================
// BUILD INCIDENT DISCORD MESSAGE — v9
// Menampilkan source form agar teknisi tahu asal tiket
// ================================================================
const parsed = $('Parse & Classify').item.json;

// Gabungkan hasil dari semua branch
let ticket = null;
try { ticket = $('API: Update Status').item.json.ticket; } catch (_) {}
try { if (!ticket) ticket = $('API: Manual Broadcast').item.json.ticket; } catch (_) {}
try {
  if (!ticket) {
    const fetched = $('Fetch Ticket Detail').item.json;
    ticket = fetched.ticket || null;
  }
} catch (_) {}

const STATUS_LABELS = {
  OPEN:        '🔴 Open',
  INVESTIGASI: '🟡 Investigating',
  MITIGASI:    '🟠 Mitigating',
  RESOLVED:    '🟢 Resolved',
  DONE:        '🟢 Resolved',
};

const ff          = ticket?.formFields || ticket?.form_fields || parsed.formFields || {};
const status      = ticket?.status || ticket?.statusPengusulan || 'OPEN';
const statusLabel = STATUS_LABELS[status.toUpperCase()] || '🔴 Open';
const title       = ff['Incident Title'] || ff['Incident Information'] || `Incident #${parsed.ticketId}`;
const priority    = ff['Priority Incident'] || 'Medium';
const severity    = ff['Severity Incident'] || 'Medium';
const suspectArea = ff['Suspect Area'] || '-';
const note        = parsed.note || '';
const source      = parsed.sourceLabel || parsed.formId || 'Unknown';
const autoDetectedNote = parsed.autoDetected ? '\n⚠️ *Auto-detected dari ticket SUPPORT*' : '';

const discordMsg = [
  '━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━',
  `🚨 **INCIDENT ${parsed.eventType === 'status_update' ? 'STATUS UPDATE' : 'BROADCAST'} — #${parsed.ticketId}**`,
  '━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━',
  `**Title      :** ${title}`,
  `**Status     :** ${statusLabel}`,
  `**Category   :** ${parsed.category.toUpperCase()}`,
  `**Priority   :** ${priority}`,
  `**Severity   :** ${severity}`,
  `**Suspect    :** ${suspectArea}`,
  `**Source     :** ${source}`,
  note ? `\n📝 **Update:** ${note}` : '',
  autoDetectedNote,
  '━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━',
].filter(Boolean).join('\n');

console.log(`[INC] Built message for #${parsed.ticketId} | source=${source} | status=${status}`);

return [{ json: {
  ticketId:    parsed.ticketId,
  category:    parsed.category,
  status,
  statusLabel,
  sourceLabel: source,
  discordMsg,
  eventType:   parsed.eventType,
  ok:          true,
} }];
